const input = $input.first().json;
const leadId = input.lead_id;
const phone  = input.phone;
const optOut = input.opt_out === true || input.opt_out === 'true';

if (optOut) {
  return [{ json: { pass: false, reason: 'optout', lead_id: leadId, phone } }];
}

// Horário comercial: 08:00–20:00, excluindo domingo (0)
const now = new Date();
const spTime = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const hour = spTime.getHours();
const weekday = spTime.getDay(); // 0=Dom, 6=Sab

if (weekday === 0 || hour < 8 || hour >= 20) {
  return [{ json: { pass: false, reason: 'horario', lead_id: leadId, phone } }];
}

return [{ json: { pass: true, reason: '', lead_id: leadId, phone } }];
